type TestClient = {
	readyState: number;
	bufferedAmount: number;
	sent: any[];
	send(data: string): void;
	close(code?: number, reason?: string): void;
};

const managers: any[] = [];

function makeClient(): TestClient {
	return {
		readyState: 1,
		bufferedAmount: 0,
		sent: [],
		send(data: string) { this.sent.push(JSON.parse(data)); },
		close() { this.readyState = 3; },
	};
}

function deferred<T>() {
	let resolve!: (value: T) => void;
	let reject!: (reason?: unknown) => void;
	const promise = new Promise<T>((res, rej) => { resolve = res; reject = rej; });
	return { promise, resolve, reject };
}

function makeManager(): any {
	const clock = createManualClock();
	const manager: any = new SessionManager({ clock });
	// Stop the status heartbeat interval so advancing the virtual clock only
	// drives the auto-retry setTimeout timers under test (the original suite faked
	// setTimeout only, leaving the setInterval heartbeat dormant).
	if (manager._statusHeartbeatTimer) { clock.clearInterval(manager._statusHeartbeatTimer); manager._statusHeartbeatTimer = null; }
	manager._testClock = clock;
	manager._testStore = {
		update: vi.fn(() => {}),
		get: vi.fn(() => undefined),
	};
	managers.push(manager);
	return manager;
}

function cleanupManager(manager: any): void {
	if (manager._statusHeartbeatTimer) {
		clearInterval(manager._statusHeartbeatTimer);
		manager._statusHeartbeatTimer = null;
	}
	for (const session of manager.sessions?.values?.() ?? []) {
		if (session.pendingAutoRetryTimer) clearTimeout(session.pendingAutoRetryTimer);
	}
	manager.sessionsWithConnectedClients?.clear();
	manager.sessions?.clear();
}

function putSession(manager: any, overrides: Record<string, any> = {}): any {
	const client = makeClient();
	const session = {
		id: "s-direct",
		title: "Direct prompt test",
		titleGenerated: true,
		cwd: tmpRoot,
		status: "idle",
		statusVersion: 0,
		createdAt: Date.now(),
		lastActivity: Date.now(),
		clients: new Set([client]),
		promptQueue: new PromptQueue(),
		eventBuffer: new EventBuffer(),
		streamingStartedAt: undefined,
		modelProvider: "openrouter",
		rpcClient: { prompt: vi.fn(async () => ({ success: true })) },
		...overrides,
	};
	manager.sessions.set(session.id, session);
	return { session, client };
}

function autoRetryPendingEvents(session: any): any[] {
	return session.eventBuffer
		.getAll()
		.map((entry: any) => entry.event)
		.filter((event: any) => event?.type === "auto_retry_pending");
}

function autoRetryCancelledEvents(session: any): any[] {
	return session.eventBuffer
		.getAll()
		.map((entry: any) => entry.event)
		.filter((event: any) => event?.type === "auto_retry_cancelled");
}

function assertLocalUserSteerLedger(ledger: any, text: string): void {
	assert.ok(Array.isArray(ledger));
	assert.equal(ledger.length, 1);
	assert.equal(ledger[0]?.text, text);
	assert.equal(ledger[0]?.source, "user");
	assert.match(ledger[0]?.promptId ?? "", /^steer:[a-f0-9]{64}$/);
	assert.deepEqual(ledger[0]?.author, {
		kind: "user",
		id: "user:local",
		label: "User",
	});
}

async function flushAutoRetryMicrotasks(): Promise<void> {
	await Promise.resolve();
	await Promise.resolve();
	await Promise.resolve();
	await Promise.resolve();
}

